sql:
SELECT product_images.product_id, product_images.image_url, product_videos.video_url
FROM product_images
INNER JOIN product_videos ON product_images.product_id = product_videos.product_id;

SELECT DISTINCT pv.product_id, pv.video_url
FROM product_videos pv
INNER JOIN product_images pi ON pv.product_id = pi.product_id;

SELECT product_id, video_url
FROM product_videos
WHERE product_id = 1 AND video_id > 0;

SELECT 
    (SELECT GROUP_CONCAT(image_url) FROM product_images WHERE product_id = 1) AS image_urls,
    (SELECT GROUP_CONCAT(video_url) FROM product_videos WHERE product_id = 1) AS video_urls;

SELECT product_id FROM product_images
INTERSECT
SELECT product_id FROM product_videos;

SELECT pi.product_id, pi.image_url, pv.video_url
FROM product_images AS pi
INNER JOIN product_videos AS pv ON pi.product_id = pv.product_id;

SELECT product_id FROM product_images
INTERSECT
SELECT product_id FROM product_videos;

SELECT DISTINCT pi.product_id
FROM product_images pi
INNER JOIN product_videos pv ON pi.product_id = pv.product_id;

SELECT COUNT(DISTINCT pi.product_id) AS unique_product_count
FROM product_images pi
JOIN product_videos pv ON pi.product_id = pv.product_id;

SELECT pi.image_url, pv.video_url
FROM product_images pi
INNER JOIN product_videos pv ON pi.product_id = pv.product_id;

external_knowledge:
- 'products' refers to items in a product catalog;
- 'picture' and 'video' refer to the media types linked to the products;
- 'linked to them' means these media are associated with the product ID in the respective tables.

sql:
SELECT DISTINCT PI.product_id
FROM product_images PI
JOIN product_videos PV ON PI.product_id = PV.product_id;

SELECT product_id, COUNT(*) as video_count
FROM product_videos
GROUP BY product_id;

SELECT pi.image_url, pv.video_url
FROM product_images pi
INNER JOIN product_videos pv ON pi.product_id = pv.product_id;

SELECT product_images.product_id, product_images.image_url
FROM product_images
INNER JOIN product_videos ON product_images.product_id = product_videos.product_id;

SELECT pi.product_id, pi.image_url, pv.video_url
FROM product_images pi
LEFT JOIN product_videos pv ON pi.product_id = pv.product_id;

SELECT FLOOR(AVG(pi.product_id)) AS average_product_id
FROM product_images pi
INNER JOIN product_videos pv ON pi.product_id = pv.product_id;

SELECT COUNT(DISTINCT product_images.product_id)
FROM product_images
INNER JOIN product_videos ON product_images.product_id = product_videos.product_id;

SELECT DISTINCT pi.product_id
FROM product_images pi
INNER JOIN product_videos pv ON pi.product_id = pv.product_id;

SELECT DISTINCT p1.product_id
FROM product_images p1
INNER JOIN product_videos p2 ON p1.product_id = p2.product_id;

SELECT image_id, product_id, image_url
FROM product_images
ORDER BY product_id DESC;

SELECT product_id FROM product_images
INTERSECT
SELECT product_id FROM product_videos;

SELECT MAX(num_images) AS max_images
FROM (
  SELECT product_id, COUNT(image_id) AS num_images
  FROM product_images
  GROUP BY product_id
) AS product_image_counts;

SELECT video_id, product_id, video_url
FROM product_videos
WHERE product_id > 0;

SELECT QUOTE(product_id) AS quoted_product_id
FROM (
  SELECT product_id FROM product_images
  UNION
  SELECT product_id FROM product_videos
);

SELECT DISTINCT product_id FROM product_images
INTERSECT
SELECT DISTINCT product_id FROM product_videos;

SELECT COUNT(*)
FROM (
  SELECT product_id FROM product_images WHERE product_id IN (2, 3, 5, 7, 11, 13)
  UNION
  SELECT product_id FROM product_videos WHERE product_id IN (2, 3, 5, 7, 11, 13)
) AS distinct_products;

SELECT product_id FROM product_images
INTERSECT
SELECT product_id FROM product_videos;

SELECT product_id, image_url AS url FROM product_images
UNION ALL
SELECT product_id, video_url AS url FROM product_videos;

SELECT COUNT(DISTINCT p.product_id) AS product_count
FROM product_images p
INNER JOIN product_videos v ON p.product_id = v.product_id;
